def getId_lable(batch_lable, loc_info, loc_info_ent):
    # lable_batch = batch_lable.transpose(0, 1)
    # cluster_lable_batch = torch.Tensor(lable_batch.shape).cuda()
    # for index, num in zip(cluster_index, range(len(cluster_index))):
    #    cluster_lable_batch[index] = torch.where(lable_batch[index] == 1, float(num), float(-1))
    # cluster_batch_lable = cluster_lable_batch.transpose(0, 1)
    # cluster_batch_lable_index = cluster_batch_lable[torch.gt(cluster_batch_lable, -1)]
    # cluster_batch_lable_index = cluster_batch_lable_index.long()

    lable_batch = batch_lable.transpose(0, 1)
    cluster_batch_lable = torch.Tensor(len(cluster_index), batch_lable.size(0)).cuda()
    for index, num in zip(cluster_index, range(len(cluster_index))):
        index_value, _ = torch.max(lable_batch[index], dim=0)
        cluster_batch_lable[num] = index_value
    batch_lable = cluster_batch_lable.transpose(0, 1)
    batch_lable_sum = torch.sum(batch_lable, dim=1)
    batch_lable_index = torch.nonzero(batch_lable).transpose(0, 1)
    batch_lable_index = batch_lable_index[1]

    batch_lable_sum_loc = torch.ones(loc_info.shape).cuda().view(-1).repeat(2)
    batch_lable_sum_loc_ent_ = (torch.ones(loc_info_ent.shape)).cuda().view(-1).repeat(2)
    batch_lable_sum = torch.cat([batch_lable_sum, batch_lable_sum_loc], dim=0)
    batch_lable_sum = torch.cat([batch_lable_sum, batch_lable_sum_loc_ent_], dim=0)
    batch_lable_index_loc = loc_info.view(-1).repeat(2)
    batch_lable_index_loc_ent_ = loc_info_ent.view(-1).repeat(2)
    batch_lable_index = torch.cat([batch_lable_index, batch_lable_index_loc], dim=0)
    batch_lable_index = torch.cat([batch_lable_index, batch_lable_index_loc_ent_], dim=0)
    return batch_lable_sum, batch_lable_index

def main(args):

    use_cuda = True and torch.cuda.is_available()
    data_path = os.path.join('./data', 'FB15kET') # './data/FB15kET'
    save_path = os.path.join('save', 'SFNA2') # './save/SFNA'

    # return json format
    e2id = read_id(os.path.join(data_path, 'entities.tsv')) # entity2id
    r2id = read_id(os.path.join(data_path, 'relations.tsv')) # relation2id
    t2id = read_id(os.path.join(data_path, 'types.tsv')) # type2id
    c2id = read_id(os.path.join(data_path, 'clusters.tsv')) # clusters2id # clusters.tsv --hongbin
    num_entities = len(e2id) # 14951
    num_rels = len(r2id) # 1345
    num_types = len(t2id) # 3584
    num_clusters = len(c2id) # 1081
    # shape(14951, 3584) ('0'/ '1' symbol)
    train_type_label, test_type_label = load_train_all_labels(data_path, e2id, t2id)
    # for i,j in enumerate(train_type_label):
    #    if torch.eq(j, 0).all():
    #        print('id:'+str(i))
    #        # print('value:'+str(j))
    # if use_cuda:
    #     # shape(14951, 6, 2) (c2id+len(r2id), t2id+len(e2id)) form ent2pair.npy
    #     sample_ent2pair = torch.LongTensor(load_entity_cluster_type_pair_context(args, r2id, e2id)).cuda()
    # ent_type_select = sample_ent2pair[:, :, 0] - num_rels + num_clusters
    train_dataset = ETDataset(args, "LMET_train.txt", e2id, r2id, t2id, c2id, 'train')
    valid_dataset = ETDataset(args, "LMET_valid.txt", e2id, r2id, t2id, c2id, 'valid')
    test_dataset = ETDataset(args, "LMET_test.txt", e2id, r2id, t2id, c2id, 'test')

    train_dataloader = DataLoader(train_dataset,
                                  batch_size=128, # 128
                                  shuffle=True,
                                  collate_fn=ETDataset.collate_fn,
                                  num_workers=6,
                                  worker_init_fn=seed_worker,
                                  generator=g)
    valid_dataloader = DataLoader(valid_dataset,
                                  batch_size=128,
                                  shuffle=False,
                                  collate_fn=ETDataset.collate_fn,
                                  num_workers=6,
                                  worker_init_fn=seed_worker,
                                  generator=g)
    test_dataloader = DataLoader(test_dataset,
                                  batch_size=1, # 1
                                  shuffle=False,
                                  collate_fn=ETDataset.collate_fn,
                                  num_workers=6,
                                  worker_init_fn=seed_worker,
                                  generator=g)

    model = TET(args, num_entities, num_rels, num_types, num_clusters)

    if use_cuda:
        model = model.to('cuda')
    for name, param in model.named_parameters():
        logging.debug('Parameter %s: %s, require_grad=%s' % (name, str(param.size()), str(param.requires_grad)))

    current_learning_rate = 0.001 # 0.001
    warm_up_steps = 50 # 50
    optimizer = torch.optim.Adam(
        filter(lambda p: p.requires_grad, model.parameters()),
        lr=current_learning_rate
    )

    max_valid_mrr = 0 # MRR
    model.train()
    for epoch in range(500): # 500
        log = []
        for sample_et_content, sample_kg_content, gt_ent in train_dataloader:
            type_label = train_type_label[gt_ent, :] # shape(128, 3584)
            if use_cuda:
                sample_et_content = sample_et_content.cuda()
                # print('sample_et_content.shape' + str(sample_et_content[:, :, 1].shape)) # torch.Size([128, 3])
                # print('sample_et_content' + str(sample_et_content[:, :, 1]))
                sample_kg_content = sample_kg_content.cuda()
                # print('sample_kg_content.shape' + str(sample_kg_content[:, :, 1].shape))
                # print('sample_kg_content' + str(sample_kg_content[:, :, 1]))
                type_label = type_label.cuda()
            # shape(128, len([[e2id, c2id+len(r2id), t2id+len(e2id)]]), 3)
            # shape(128, len([[e2id, r2id / len(r2id)+len(c2id)+r2id, e2id]]), 3)
            # shape(14951, 6, 2) (c2id+len(r2id), t2id+len(e2id)) form ent2pair.npy
            type_predict, context_cls, local_cls, global_cls, local_ent, global_ent = model(sample_et_content, sample_kg_content, flag=True) # global_cls, global_ent, glo_cls
            # flops, params = profile(model, (sample_et_content, sample_kg_content, True,)) # flops, params
            # print('train_flops: %.2f M, train_params: %.2f M' % (flops / 1000000.0, params / 1000000.0))
            ctx_glob = torch.cat([context_cls, local_cls.reshape(-1, 1, 300)], dim=0)
            ctx_glob = torch.cat([ctx_glob, global_cls.reshape(-1, 1, 300)], dim=0)
            ctx_glob = torch.cat([ctx_glob, local_ent.reshape(-1, 1, 300)], dim=0)
            ctx_glob = torch.cat([ctx_glob, global_ent.reshape(-1, 1, 300)], dim=0)
            sample_kg_index = torch.where(sample_kg_content[:, :, 1] < num_rels, sample_kg_content[:, :, 1],
                                          sample_kg_content[:, :, 1] - num_clusters)
            cl_sum, cl_lable = getId_lable(type_label,
            sample_et_content[:, :, 1] + num_clusters, sample_kg_index + num_clusters + num_clusters)
            new_context_cls = torch.Tensor().cuda()
            for i, j in zip(cl_sum, ctx_glob):
                data = j.repeat(int(i), 1)
                new_context_cls = torch.cat([new_context_cls, data], dim=0)

            # if args['loss'] == 'BCE':
            #     bce_loss = torch.nn.BCELoss()
            #     type_loss = bce_loss(type_predict, type_label)
            #     type_pos_loss, type_neg_loss = type_loss, type_loss
            # elif args['loss'] == 'SFNA':
            type_pos_loss, type_neg_loss = slight_fna_loss(type_predict, type_label, 1.0) # 1.0
            # print(cl_lable)
            # print(context_cls.shape)
            # print(global_cls.shape)
            cl_loss = translation_cl_loss(new_context_cls, cl_lable, args['cl_loss_temperature'])
            # print(context_cl_loss,global_cl_loss)
            type_loss = type_pos_loss + type_neg_loss
            type_loss = type_loss + args['cl_loss_weight'] * cl_loss
            # else:
            #     raise ValueError('loss %s is not defined' % args['loss'])

            log.append({
                "loss": type_loss.item(),
                "pos_loss": type_pos_loss.item(),
                "neg_loss": type_neg_loss.item(),
                "cl_loss": cl_loss.item(),
            })

            optimizer.zero_grad()
            type_loss.requires_grad_(True)
            type_loss.backward()
            optimizer.step()

        if epoch >= warm_up_steps: # 50
            current_learning_rate = current_learning_rate / 5 # 0.001
            optimizer = torch.optim.Adam(
                filter(lambda p: p.requires_grad, model.parameters()),
                lr=current_learning_rate
            )
            warm_up_steps = warm_up_steps * 2

        avg_type_loss = sum([_['loss'] for _ in log]) / len(log)
        avg_type_pos_loss = sum([_['pos_loss'] for _ in log]) / len(log)
        avg_type_neg_loss = sum([_['neg_loss'] for _ in log]) / len(log)
        avg_cl_loss = sum([_['cl_loss'] for _ in log]) / len(log)
        logging.debug('epoch %d: loss: %f\tpos_loss: %f\tneg_loss: %f\tcl_loss: %f' %
                       (epoch, avg_type_loss, avg_type_pos_loss, avg_type_neg_loss, avg_cl_loss))

        if epoch != 0 and epoch % 25 == 0:
            model.eval()
            with torch.no_grad():
                logging.debug('-----------------------valid step-----------------------')
                predict = torch.zeros(num_entities, num_types, dtype=torch.half) # 14951, 3584
                for sample_et_content, sample_kg_content, gt_ent in valid_dataloader:
                    if use_cuda:
                        sample_et_content = sample_et_content.cuda()
                        sample_kg_content = sample_kg_content.cuda()
                    predict[gt_ent] = model(sample_et_content, sample_kg_content, flag=False)[0].cpu().half()
                valid_mrr = evaluate(os.path.join(data_path, 'ET_valid.txt'), predict, test_type_label, e2id, t2id)

                logging.debug('-----------------------test step-----------------------')
                predict = torch.zeros(num_entities, num_types, dtype=torch.half)
                for sample_et_content, sample_kg_content, gt_ent in test_dataloader:
                    if use_cuda:
                        sample_et_content = sample_et_content.cuda()
                        sample_kg_content = sample_kg_content.cuda()
                    predict[gt_ent] = model(sample_et_content, sample_kg_content, flag=False)[0].cpu().half()
                    # flops, params = profile(model, (sample_et_content, sample_kg_content, False,)) # flops, params
                    # print('test_flops: %.2f M, test_params: %.2f M' % (flops / 1000000.0, params / 1000000.0))
                evaluate(os.path.join(data_path, 'ET_test.txt'), predict, test_type_label, e2id, t2id)

            model.train()
            if valid_mrr < max_valid_mrr:
                logging.debug('early stop')
                break
            else:
                torch.save(model.state_dict(), os.path.join(save_path, 'best_model.pkl'))
                max_valid_mrr = valid_mrr

                # save embedding
                entity_embedding = model.entity.detach().cpu().numpy()
                np.save(
                    os.path.join(save_path, 'entity_embedding'),
                    entity_embedding
                )
                relation_embedding = model.relation.detach().cpu().numpy()
                np.save(
                    os.path.join(save_path, 'relation_embedding'),
                    relation_embedding
                )

    logging.debug('-----------------------best test step-----------------------')
    with torch.no_grad():
        model.load_state_dict(torch.load(os.path.join(save_path, 'best_model.pkl')))
        model.eval()
        predict = torch.zeros(num_entities, num_types, dtype=torch.half)
        for sample_et_content, sample_kg_content, gt_ent in test_dataloader:
            if use_cuda:
                sample_et_content = sample_et_content.cuda()
                sample_kg_content = sample_kg_content.cuda()
            predict[gt_ent] = model(sample_et_content, sample_kg_content, flag=False)[0].cpu().half()

    eval_result = evaluate(os.path.join(data_path, 'ET_test.txt'), predict, test_type_label, e2id, t2id)
    # 释放模型内存
    # del model

    return eval_result


