def hyperparameter_tuning(params):
    print(' cl_loss_temperature: ' + str(params["cl_loss_temperature"])
          + ' cl_loss_weight: ' + str(params["cl_loss_weight"])
          + ' sample_et_size:' + str(params["sample_et_size"])
          + ' sample_kg_size :' + str(params["sample_kg_size"]))
    return - main(params)

# 定义参数优化函数
def param_hyperopt(max_evals=50):
    trials = Trials()
    # # 提前停止条件
    # early_stop_fn = no_progress_loss(20)
    # 优化模型
    params_best = fmin(fn=hyperparameter_tuning, space=space, algo=atpe.suggest, max_evals=max_evals,
                       trials=trials) #, early_stop_fn=early_stop_fn)
    print('best params:', params_best)
    print('trials:')
    for trial in trials.trials[:]:
        print(trial)
    return params_best, trials


